import{_ as n,H as s,f as a,i as e}from"./chunks/framework.DLd0CbzH.js";const u=JSON.parse('{"title":"技术架构与目录结构","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),l={name:"guide/architecture.md"};function p(i,t,d,r,o,g){return s(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="技术架构与目录结构" tabindex="-1">技术架构与目录结构 <a class="header-anchor" href="#技术架构与目录结构" aria-label="Permalink to &quot;技术架构与目录结构&quot;">​</a></h1><p><code>unibestX</code> 基于最新的前端构建工具和 uni-app 原生渲染技术，旨在提供极致的性能和开发体验。</p><h2 id="🛠️-核心技术栈" tabindex="-1">🛠️ 核心技术栈 <a class="header-anchor" href="#🛠️-核心技术栈" aria-label="Permalink to &quot;🛠️ 核心技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">技术</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>框架</strong></td><td style="text-align:left;">uni-app X</td><td style="text-align:left;">下一代 uni-app，基于原生渲染，彻底告别 Webview 的性能瓶颈</td></tr><tr><td style="text-align:left;"><strong>语言</strong></td><td style="text-align:left;">UTS</td><td style="text-align:left;">uni-app Type Script，编译期直接转换为原生 Kotlin(Android) 和 Swift(iOS)</td></tr><tr><td style="text-align:left;"><strong>前端框架</strong></td><td style="text-align:left;">Vue 3</td><td style="text-align:left;">采用 Composition API 编写 UI 逻辑</td></tr><tr><td style="text-align:left;"><strong>构建工具</strong></td><td style="text-align:left;">Vite 5</td><td style="text-align:left;">提供极速的本地开发启动与热更新体验</td></tr><tr><td style="text-align:left;"><strong>CSS 引擎</strong></td><td style="text-align:left;">UnoCSS</td><td style="text-align:left;">按需生成的原子化 CSS，轻量且高效</td></tr><tr><td style="text-align:left;"><strong>UI 组件库</strong></td><td style="text-align:left;">uview-ultra</td><td style="text-align:left;">专为 uni-app X 深度重构的组件库，修复了原生 <code>gap</code>/<code>grid</code> 等布局限制</td></tr><tr><td style="text-align:left;"><strong>分页组件</strong></td><td style="text-align:left;">z-paging-x</td><td style="text-align:left;">提供强大的下拉刷新与分页列表加载体验</td></tr><tr><td style="text-align:left;"><strong>状态管理</strong></td><td style="text-align:left;">x-pinia-s</td><td style="text-align:left;">兼容 uni-app X 的 Pinia 方案</td></tr><tr><td style="text-align:left;"><strong>HTTP 请求</strong></td><td style="text-align:left;">lime-request</td><td style="text-align:left;">uni-app X 兼容的现代化请求库</td></tr><tr><td style="text-align:left;"><strong>国际化</strong></td><td style="text-align:left;">lime-i18n</td><td style="text-align:left;">兼容 vue-i18n 生态的多语言方案</td></tr><tr><td style="text-align:left;"><strong>图表库</strong></td><td style="text-align:left;">e-chart</td><td style="text-align:left;">ECharts 在 uni-app X 中的适配实现</td></tr></tbody></table><h2 id="📁-项目目录结构" tabindex="-1">📁 项目目录结构 <a class="header-anchor" href="#📁-项目目录结构" aria-label="Permalink to &quot;📁 项目目录结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>unibestX/</span></span>
<span class="line"><span>├── plugins/               # Vite 插件（包含自定义的布局、根组件注入插件）</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── api/               # 各个业务模块的 API 请求函数</span></span>
<span class="line"><span>│   ├── components/        # 公共 Vue/UTS 组件（NavBar, Tabs 等）</span></span>
<span class="line"><span>│   ├── http/              # HTTP 请求客户端封装与响应类型定义</span></span>
<span class="line"><span>│   ├── i18n/              # 国际化配置实例及语言包（zh-CN / en-US）</span></span>
<span class="line"><span>│   ├── layouts/           # 页面布局模板配置（如 default.uvue）</span></span>
<span class="line"><span>│   ├── pages/             # 主应用页面（通常是 TabBar 包含的页面）</span></span>
<span class="line"><span>│   ├── router/            # 全局路由拦截与登录黑白名单策略</span></span>
<span class="line"><span>│   ├── store/             # Pinia 状态管理（app, user, token）</span></span>
<span class="line"><span>│   ├── style/             # 全局样式（UnoCSS / SCSS）</span></span>
<span class="line"><span>│   ├── sub/               # 应用分包页面（登录页、组件演示、分页演示等）</span></span>
<span class="line"><span>│   ├── tabbar/            # 自定义 TabBar 组件及配置</span></span>
<span class="line"><span>│   └── utils/             # 全局工具函数（提示、系统信息、双击退出等）</span></span>
<span class="line"><span>├── uni_modules/           # uni-app 官方与第三方插件市场模块</span></span>
<span class="line"><span>├── js_sdk/                # JavaScript/UTS SDK 资源</span></span>
<span class="line"><span>├── App.ku.uvue            # 全局根组件，提供主题、全局 Toast 容器</span></span>
<span class="line"><span>├── main.uts               # 应用的入口文件</span></span>
<span class="line"><span>├── pages.json             # 页面路由表与构建配置</span></span>
<span class="line"><span>├── manifest.json          # 应用配置清单（AppID、权限等）</span></span>
<span class="line"><span>├── vite.config.ts         # Vite 构建配置（插件、别名等）</span></span>
<span class="line"><span>├── uni.scss               # 全局 SCSS 变量注入</span></span>
<span class="line"><span>└── tsconfig.json          # TypeScript/UTS 编译配置</span></span></code></pre></div>`,6)])])}const f=n(l,[["render",p]]);export{u as __pageData,f as default};
